+                &id,
+                InvalidationReason::OperatorInvalidation {
+                    reason: "det".into(),
+                },
+                2000,
+            )
+            .unwrap()
+    };
+
+    let r1 = make_receipt(0);
+    let r2 = make_receipt(1);
+    assert_ne!(r1.signature, r2.signature);
